#### Unit Tests
```rust
#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_orphan_detection() {
        let issues = vec![
            make_issue_with_parent("a", None),      // orphan
            make_issue_with_parent("b", Some("x")), // has parent
            make_issue_with_parent("c", None),      // orphan
        ];
        let orphans = find_orphans(&issues);
        assert_eq!(orphans.len(), 2);
        assert!(orphans.iter().any(|i| i.id == "a"));
        assert!(orphans.iter().any(|i| i.id == "c"));
    }

    #[test]
    fn test_orphans_panel_formatting() {
        let orphans = vec![
            make_issue("orphan-1", "Fix auth bug", Priority::HIGH),
            make_issue("orphan-2", "Update docs", Priority::MEDIUM),
        ];
        let ctx = OutputContext::rich();
        let output = format_orphans(&orphans, &ctx);
        assert!(output.contains("orphan-1"));
        assert!(output.contains("orphan-2"));
        assert!(output.contains("12") || output.contains("2")); // count
    }

    #[test]
    fn test_orphans_suggestion_included() {
        let orphans = vec![make_issue("test-1", "Test", Priority::LOW)];
        let ctx = OutputContext::rich();
        let output = format_orphans(&orphans, &ctx);
        assert!(output.contains("Suggestion") || output.contains("parent"));
    }

    #[test]
    fn test_no_orphans_message() {
        let orphans: Vec<Issue> = vec![];
        let ctx = OutputContext::rich();
        let output = format_orphans(&orphans, &ctx);
        assert!(output.contains("No") || output.contains("0") || output.contains("none"));
    }

    #[test]
    fn test_json_mode_orphans() {
        let orphans = vec![make_issue("test-1", "Test", Priority::LOW)];
        let ctx = OutputContext::json();
        let output = format_orphans(&orphans, &ctx);
        let parsed: serde_json::Value = serde_json::from_str(&output).unwrap();
        assert!(parsed.is_array());
        assert_eq!(parsed[0]["id"], "test-1");
    }
}
```

