#[test]
fn test_orphans_finds_unparented() {
    let (mut storage, dir) = test_db_with_dir();
    init_test_project(&dir);

    // Create orphan issue (no parent)
    create_test_issue(&mut storage, "Orphan issue");

    // Create epic and child
    let epic_id = create_test_issue_with_type(&mut storage, "Epic", IssueType::Epic);
    let child_id = create_test_issue(&mut storage, "Child");
    set_parent(&mut storage, &child_id, &epic_id);

    let result = run_orphans_command(&dir);
    assert!(result.is_ok());
    let output = result.unwrap();
    assert!(output.contains("Orphan issue"));
    assert!(!output.contains("Child"));
}

#[test]
fn test_orphans_excludes_epics() {
    let (mut storage, dir) = test_db_with_dir();
    init_test_project(&dir);

    // Epics themselves shouldn't be counted as orphans
    create_test_issue_with_type(&mut storage, "Epic", IssueType::Epic);

    let result = run_orphans_command(&dir);
    assert!(result.is_ok());
    // Epic should not appear in orphans
}
```

#### E2E Test Script
```bash
#!/bin/bash
set -euo pipefail
source "$(dirname "$0")/../common/test_helpers.sh"

log_info "=== E2E: Orphans Command ==="
setup_test_db

log_step "Initialize and create test data"
br init --prefix test
ORPHAN_ID=$(br create "Orphan issue" --silent)
EPIC_ID=$(br create "Test Epic" --type epic --silent)
CHILD_ID=$(br create "Child issue" --parent "$EPIC_ID" --silent)

log_step "Testing orphans detection"
ORPHANS_OUTPUT=$(br orphans)
log_debug "Orphans output: $ORPHANS_OUTPUT"
if echo "$ORPHANS_OUTPUT" | grep -q "$ORPHAN_ID"; then
    log_pass "Orphan issue detected"
else
    log_fail "Orphan issue not found"
    exit 1
fi

log_step "Verifying child not in orphans"
if echo "$ORPHANS_OUTPUT" | grep -q "$CHILD_ID"; then
    log_fail "Child issue incorrectly marked as orphan"
    exit 1
else
    log_pass "Child issue correctly excluded"
fi

log_step "Testing JSON output"
ORPHANS_JSON=$(br orphans --json)
log_debug "JSON: $ORPHANS_JSON"
echo "$ORPHANS_JSON" | jq -e '.'
log_pass "Orphans JSON valid"

log_pass "=== All orphans tests passed ==="
